#!/usr/bin/env python3
"""Block recursive functions introduced via Edit to prevent unbounded recursion."""
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}

    # Collect all new code being added
    new_strs = []
    if "new_string" in inp:
        new_strs.append(inp["new_string"])
    if "edits" in inp:
        for e in inp.get("edits", []):
            if "new_string" in e:
                new_strs.append(e["new_string"])

    # Check each new code section for direct recursion
    detected = []
    for new_str in new_strs:
        lines = new_str.split("\n")
        for i, line in enumerate(lines):
            # Match function definitions
            m = re.match(r"\s*(?:async\s+)?def\s+(\w+)\s*\(", line)
            if not m:
                continue
            func_name = m.group(1)

            # Check if function body contains a call to the same function
            func_body = "\n".join(lines[i+1:])
            if re.search(rf"\b{re.escape(func_name)}\s*\(", func_body):
                detected.append(func_name)

    if detected:
        print(
            f"BLOCKING: Recursive function(s) detected: {', '.join(set(detected))}. "
            f"Rewrite with iterative implementation (worklist/stack pattern). Do not retry.",
            file=sys.stderr
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Auto-format Python files with ruff after any Edit/MultiEdit."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path or not file_path.endswith(".py"):
        return 0

    if not os.path.exists(file_path):
        return 0

    try:
        result = subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            text=True,
            timeout=10
        )
        if result.returncode != 0:
            print(
                f"ruff format error on {os.path.basename(file_path)}:\n{result.stderr}",
                file=sys.stderr
            )
    except FileNotFoundError:
        return 0
    except Exception:
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After ruff check fails with formatting errors, suggest ruff format."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Bash":
        return 0

    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "")

    if "ruff check" not in cmd:
        return 0

    resp = ev.get("tool_response") or {}
    exit_code = resp.get("exit_code", 0)
    stderr = resp.get("stderr", "")

    if exit_code == 0:
        return 0

    formatting_keywords = ["indentation", "trailing whitespace", "line too long", "quote"]
    has_formatting_issue = any(kw in stderr.lower() for kw in formatting_keywords)

    if has_formatting_issue:
        print(
            "REQUIRED FOLLOW-UP: ruff check found formatting issues. Run `ruff format`, then re-check. Do not stop.",
            file=sys.stderr
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit that touches an exported identifier, grep for all
references and feed the list back to Claude so stale hardcodes can be fixed."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}

    # Build list of edits (MultiEdit has .edits; Edit has .old_string/.new_string)
    if inp.get("edits"):
        edits = inp["edits"]
    else:
        old_str = inp.get("old_string", "")
        new_str = inp.get("new_string", "")
        edits = [{"old_string": old_str, "new_string": new_str}] if (old_str or new_str) else []

    # Extract exported identifier names
    names: set = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    # Grep for each identifier name
    cwd = ev.get("cwd", ".")
    for name in sorted(names):
        try:
            r = subprocess.run(
                ["grep", "-rn", "-w", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, cwd],
                capture_output=True, text=True, timeout=5, cwd=cwd
            )
            hits = [l for l in r.stdout.splitlines() if l][:30]
            if hits:
                print(f"BLOCKING: exported `{name}` was edited. {len(hits)} reference(s) found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Update each reference as needed, then proceed. Do not stop.", file=sys.stderr)
                return 2
        except Exception:
            pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block git force-pushes (-f / --force)."""
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if "git" in cmd and "push" in cmd:
        if "--force" in cmd or re.search(r'-f(?:\s|$)', cmd):
            print("Blocked: force-pushes rewrite history. Use --force-with-lease or a regular push.", file=sys.stderr)
            return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())
